
CREATE PROCEDURE AX2009.usp_Merge_INVENTTABLE_ArticoloConfigurato
AS
BEGIN
SET NOCOUNT ON;

IF OBJECT_ID(N'AX2009.INVENTTABLE_ArticoloConfigurato', N'U') IS NULL
BEGIN
    EXEC AX2009.usp_Create_INVENTTABLE_ArticoloConfigurato;
    EXEC AX2009.usp_AddIndexes_INVENTTABLE_ArticoloConfigurato;
END;

MERGE INTO AX2009.INVENTTABLE_ArticoloConfigurato AS TGT
USING AX2009.INVENTTABLE_ArticoloConfiguratoView (nolock) AS SRC
ON SRC.DATAAREAID = TGT.DATAAREAID AND SRC.ITEMID = TGT.ITEMID
WHEN MATCHED AND (TGT.ITEMGROUPID <> SRC.ITEMGROUPID OR TGT.ITEMNAME <> SRC.ITEMNAME OR TGT.ITEMTYPE <> SRC.ITEMTYPE OR TGT.REQGROUPID <> SRC.REQGROUPID OR TGT.PRIMARYVENDORID <> SRC.PRIMARYVENDORID OR TGT.DIMENSION <> SRC.DIMENSION OR TGT.DIMENSION2_ <> SRC.DIMENSION2_ OR TGT.DIMENSION3_ <> SRC.DIMENSION3_ OR TGT.DIMENSION4_ <> SRC.DIMENSION4_ OR TGT.DIMENSION5_ <> SRC.DIMENSION5_ OR TGT.DIMENSION6_ <> SRC.DIMENSION6_ OR TGT.INTRACODE <> SRC.INTRACODE OR TGT.PBAITEMAUTOGENERATED <> SRC.PBAITEMAUTOGENERATED OR TGT.STOPEXPLODE <> SRC.STOPEXPLODE OR TGT.COMMISSIONGROUPID <> SRC.COMMISSIONGROUPID OR TGT.FISCALLIFOAVOIDCALC <> SRC.FISCALLIFOAVOIDCALC OR TGT.BOMCALCGROUPID <> SRC.BOMCALCGROUPID OR TGT.PBAITEMCONFIGURABLE <> SRC.PBAITEMCONFIGURABLE OR TGT.NETWEIGHT_KG <> SRC.NETWEIGHT_KG OR TGT.NPOPBAREFITEMID <> SRC.NPOPBAREFITEMID OR TGT.NPOASITEMALIAS <> SRC.NPOASITEMALIAS OR TGT.NPOINVENTITEMTYPE <> SRC.NPOINVENTITEMTYPE OR TGT.NPOWRKCTRGROUPID <> SRC.NPOWRKCTRGROUPID OR TGT.NPOINVENTABCCODE <> SRC.NPOINVENTABCCODE OR TGT.NPOITEMLENGTH <> SRC.NPOITEMLENGTH OR TGT.NPOITEMFINISHINGID <> SRC.NPOITEMFINISHINGID OR TGT.NPOREVENUERAWTYPE <> SRC.NPOREVENUERAWTYPE OR TGT.NPOREVENUEGROUPID <> SRC.NPOREVENUEGROUPID OR TGT.NCESCRAPITEMID <> SRC.NCESCRAPITEMID OR TGT.CREATEDDATETIME <> SRC.CREATEDDATETIME)
  THEN UPDATE SET TGT.ITEMGROUPID = SRC.ITEMGROUPID, TGT.ITEMNAME = SRC.ITEMNAME, TGT.ITEMTYPE = SRC.ITEMTYPE, TGT.REQGROUPID = SRC.REQGROUPID, TGT.PRIMARYVENDORID = SRC.PRIMARYVENDORID, TGT.DIMENSION = SRC.DIMENSION, TGT.DIMENSION2_ = SRC.DIMENSION2_, TGT.DIMENSION3_ = SRC.DIMENSION3_, TGT.DIMENSION4_ = SRC.DIMENSION4_, TGT.DIMENSION5_ = SRC.DIMENSION5_, TGT.DIMENSION6_ = SRC.DIMENSION6_, TGT.INTRACODE = SRC.INTRACODE, TGT.PBAITEMAUTOGENERATED = SRC.PBAITEMAUTOGENERATED, TGT.STOPEXPLODE = SRC.STOPEXPLODE, TGT.COMMISSIONGROUPID = SRC.COMMISSIONGROUPID, TGT.FISCALLIFOAVOIDCALC = SRC.FISCALLIFOAVOIDCALC, TGT.BOMCALCGROUPID = SRC.BOMCALCGROUPID, TGT.PBAITEMCONFIGURABLE = SRC.PBAITEMCONFIGURABLE, TGT.NETWEIGHT_KG = SRC.NETWEIGHT_KG, TGT.NPOPBAREFITEMID = SRC.NPOPBAREFITEMID, TGT.NPOASITEMALIAS = SRC.NPOASITEMALIAS, TGT.NPOINVENTITEMTYPE = SRC.NPOINVENTITEMTYPE, TGT.NPOWRKCTRGROUPID = SRC.NPOWRKCTRGROUPID, TGT.NPOINVENTABCCODE = SRC.NPOINVENTABCCODE, TGT.NPOITEMLENGTH = SRC.NPOITEMLENGTH, TGT.NPOITEMFINISHINGID = SRC.NPOITEMFINISHINGID, TGT.NPOREVENUERAWTYPE = SRC.NPOREVENUERAWTYPE, TGT.NPOREVENUEGROUPID = SRC.NPOREVENUEGROUPID, TGT.NCESCRAPITEMID = SRC.NCESCRAPITEMID, TGT.CREATEDDATETIME = SRC.CREATEDDATETIME
WHEN NOT MATCHED
  THEN INSERT VALUES (DATAAREAID, ITEMID, RECID, ITEMGROUPID, ITEMNAME, ITEMTYPE, REQGROUPID, PRIMARYVENDORID, DIMENSION, DIMENSION2_, DIMENSION3_, DIMENSION4_, DIMENSION5_, DIMENSION6_, INTRACODE, PBAITEMAUTOGENERATED, STOPEXPLODE, COMMISSIONGROUPID, FISCALLIFOAVOIDCALC, BOMCALCGROUPID, PBAITEMCONFIGURABLE, NETWEIGHT_KG, NPOPBAREFITEMID, NPOASITEMALIAS, NPOINVENTITEMTYPE, NPOWRKCTRGROUPID, NPOINVENTABCCODE, NPOITEMLENGTH, NPOITEMFINISHINGID, NPOREVENUERAWTYPE, NPOREVENUEGROUPID, NCESCRAPITEMID, CREATEDDATETIME)
WHEN NOT MATCHED BY SOURCE
  THEN DELETE
OUTPUT
    CURRENT_TIMESTAMP AS merge_datetime,
    $action AS merge_action,
    'AX2009.INVENTTABLE_ArticoloConfigurato' AS full_olap_table_name,
    'DATAAREAID = ' + CAST(COALESCE(inserted.DATAAREAID, deleted.DATAAREAID) AS NVARCHAR) + ' - ' + 'ITEMID = ' + CAST(COALESCE(inserted.ITEMID, deleted.ITEMID) AS NVARCHAR) AS primary_key_description
INTO audit.merge_log_details;

END;
GO

